static int g_pass = 0, g_fail = 0;

static uint8_t hex_nibble(char c) {
    if (c >= '0' && c <= '9') return (uint8_t)(c - '0');
    if (c >= 'a' && c <= 'f') return (uint8_t)(c - 'a' + 10);
    if (c >= 'A' && c <= 'F') return (uint8_t)(c - 'A' + 10);
    return 0;
}

static std::array<uint8_t, 32> hex32(const char* h) {
    std::array<uint8_t, 32> out{};
    for (size_t i = 0; i < 32; ++i)
        out[i] = (uint8_t)((hex_nibble(h[2*i]) << 4) | hex_nibble(h[2*i+1]));
    return out;
}

static size_t hex_decode(const char* hex, uint8_t* out, size_t max_out) {
    size_t hex_len = strlen(hex);
    if (hex_len % 2 != 0) return 0;
    size_t n = hex_len / 2;
    if (n > max_out) return 0;
    for (size_t i = 0; i < n; ++i)
        out[i] = (uint8_t)((hex_nibble(hex[2*i]) << 4) | hex_nibble(hex[2*i+1]));
    return n;
}

// -- Strict DER ECDSA parser --------------------------------------------------
static bool der_parse_strict(const uint8_t* der, size_t len,
                              std::array<uint8_t,32>& r_out,
                              std::array<uint8_t,32>& s_out) {
    if (!der || len < 8) return false;
    size_t off = 0;
    if (der[off++] != 0x30) return false;
    // Length byte: must be short-form (< 0x80)
    uint8_t outer_len_byte = der[off++];
    if (outer_len_byte >= 0x80) return false;
    size_t outer_len = outer_len_byte;
    if (off + outer_len != len) return false;
    // r INTEGER
    if (der[off++] != 0x02) return false;
    uint8_t rlen_byte = der[off++];
    if (rlen_byte >= 0x80) return false;
    size_t rlen = rlen_byte;
    if (rlen == 0 || rlen > 33) return false;
    const uint8_t* rp = der + off; off += rlen;
    // s INTEGER
    if (off >= len || der[off++] != 0x02) return false;
    uint8_t slen_byte = der[off++];
    if (slen_byte >= 0x80) return false;
    size_t slen = slen_byte;
    if (slen == 0 || slen > 33) return false;
    const uint8_t* sp = der + off; off += slen;
    if (off != len) return false;
    // Validate integers: no negative, no extra leading zeros, no overflow padding
    if (rp[0] & 0x80) return false;  // negative — technically MissingZero if len==33
    if (rlen > 1 && rp[0] == 0 && !(rp[1] & 0x80)) return false;  // extra zero
    if (rlen == 33 && rp[0] != 0x00) return false;  // 33-byte r must be 00-padded sign ext
    if (sp[0] & 0x80) return false;
    if (slen > 1 && sp[0] == 0 && !(sp[1] & 0x80)) return false;
    if (slen == 33 && sp[0] != 0x00) return false;  // 33-byte s must be 00-padded sign ext
    // Copy to 32-byte arrays (right-align)
    r_out.fill(0); s_out.fill(0);
    size_t roff = rlen == 33 ? 1 : 0;  // skip leading 0x00 pad for sign
    size_t soff = slen == 33 ? 1 : 0;
    size_t rcopy = rlen - roff;
    size_t scopy = slen - soff;
    if (rcopy > 32 || scopy > 32) return false;
    memcpy(r_out.data() + (32 - rcopy), rp + roff, rcopy);
    memcpy(s_out.data() + (32 - scopy), sp + soff, scopy);
    // r, s must be in [1, n-1]
    static const uint8_t N[32] = {
        0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFF,0xFE,
        0xBA,0xAE,0xDC,0xE6,0xAF,0x48,0xA0,0x3B,0xBF,0xD2,0x5E,0x8C,0xD0,0x36,0x41,0x41
    };
    bool r_zero = true, s_zero = true;
    for (int i = 0; i < 32; i++) {
        if (r_out[i]) r_zero = false;
        if (s_out[i]) s_zero = false;
    }
    if (r_zero || s_zero) return false;
    // r >= N: reject
    for (int i = 0; i < 32; i++) {
        if (r_out[i] < N[i]) break;
        if (r_out[i] > N[i]) return false;
    }
    for (int i = 0; i < 32; i++) {
        if (s_out[i] < N[i]) break;
        if (s_out[i] > N[i]) return false;
    }
    return true;
}

// -- Group structs -----------------------------------------------------------
struct SigVector {
    int tcId;
    const char* msg;  // hex-encoded raw message bytes
    const char* sig;  // DER-encoded ECDSA signature hex
    int result;       // 1=valid, -1=invalid, 0=acceptable
};

struct PubKeyGroup {
    char wx[65];  // 32 bytes hex big-endian
    char wy[65];
    const SigVector* tests;
    int test_count;
};

