static void check(bool cond, const char* msg) {
    if (cond) { ++g_pass; printf("    [OK] %s\n", msg); }
    else       { ++g_fail; printf("  [FAIL] %s\n", msg); }
    fflush(stdout);
}

static void run_all_vectors() {
    constexpr size_t NG = sizeof(kGroups) / sizeof(kGroups[0]);
    int total_tested = 0, total_valid = 0, total_invalid = 0;

    for (size_t gi = 0; gi < NG; ++gi) {
        const PubKeyGroup& grp = kGroups[gi];

        // Build public key from wx/wy
        FieldElement fx = FieldElement::from_bytes(hex32(grp.wx));
        FieldElement fy = FieldElement::from_bytes(hex32(grp.wy));
        Point pk = Point::from_affine(fx, fy);
        if (pk.is_infinity()) {
            printf("  [SKIP] group %zu: invalid public key\n", gi);
            continue;
        }

        for (int ti = 0; ti < grp.test_count; ++ti) {
            const SigVector& sv = grp.tests[ti];
            ++total_tested;

            char label[80];
            snprintf(label, sizeof(label), "tcId=%d", sv.tcId);

            // Decode message bytes and compute SHA-512
            uint8_t msg_buf[4096] = {};
            size_t msg_len = hex_decode(sv.msg, msg_buf, sizeof(msg_buf));

            // SHA-512(message) -> take first 32 bytes as msg_hash32
            auto h512 = SHA512::hash(msg_buf, msg_len);
            std::array<uint8_t, 32> msg_hash{};
            memcpy(msg_hash.data(), h512.data(), 32);

            // Decode DER signature
            uint8_t sig_buf[256] = {};
            size_t sig_len = hex_decode(sv.sig, sig_buf, sizeof(sig_buf));

            std::array<uint8_t, 32> r, s;
            bool der_ok = der_parse_strict(sig_buf, sig_len, r, s);

            if (!der_ok) {
                // Cannot parse this DER
                if (sv.result == -1) {
                    char lbl[80]; snprintf(lbl, sizeof(lbl), "tcId=%d invalid-rejected", sv.tcId);
                    check(!der_ok, lbl);  // explicit: der_ok==false is the semantic assertion
                    ++total_invalid;
                } else if (sv.result == 1) {
                    char lbl[80]; snprintf(lbl, sizeof(lbl), "tcId=%d valid-should-parse", sv.tcId);
                    check(false, lbl);
                    ++total_valid;
                }
                // acceptable: skip
                continue;
            }

            // Call ecdsa_verify
            ECDSASignature sig_obj;
            sig_obj.r = Scalar::from_bytes(r);
            sig_obj.s = Scalar::from_bytes(s);
            bool verify_ok = ecdsa_verify(msg_hash.data(), pk, sig_obj);

            if (sv.result == 1) {
                char lbl[80]; snprintf(lbl, sizeof(lbl), "tcId=%d valid", sv.tcId);
                check(verify_ok, lbl);
                ++total_valid;
            } else if (sv.result == -1) {
                char lbl[80]; snprintf(lbl, sizeof(lbl), "tcId=%d invalid-rejected", sv.tcId);
                check(!verify_ok, lbl);
                ++total_invalid;
            }
            // acceptable: no assertion
        }
    }
    printf("    Tested %d vectors (%d valid, %d invalid)\n",
           total_tested, total_valid, total_invalid);
}

int test_wycheproof_ecdsa_secp256k1_sha512_run() {
    printf("====================================================================\n");
    printf("Wycheproof ECDSA secp256k1 SHA-512 DER Test Vectors (C2SP)\n");
    printf("====================================================================\n\n");
    run_all_vectors();
    printf("\n====================================================================\n");
    printf("Result: %d passed, %d failed\n", g_pass, g_fail);
    printf("====================================================================\n");
    return (g_fail > 0) ? 1 : 0;
}

#if defined(STANDALONE_TEST)
int main() {
    return test_wycheproof_ecdsa_secp256k1_sha512_run();
}
#endif